list:
footer {
	padding:10px;
	background: -webkit-linear-gradient(to left, rgba(252,252,255,0.5), #fffbe2 );
	background: linear-gradient(to left, rgba(252,252,255,0.5), #fffbe2  );
	text-align: center;
	font-size: 0.85em;
}

footer a {
	text-decoration:none;
	color:darkgreen;
	font-weight:bold;
	font-style: italic;
}

button {
	cursor: pointer;
	font-size: 101%;
	font-weight: bold;
	color: darkblue;
	margin: 2px;
	width:120px;
	border-color: rgba(248, 238, 200, 0.712);
	border-radius: 16px;
	background-color: rgba(248, 248, 255, 0.815);
	box-shadow: 3px 2px rgba(236, 236, 209, 0.74);
}

body {
	border: 1px solid black;
	-moz-box-sizing: border-box;
	box-sizing: border-box;
}

main {
	border-left: solid 3px navy;
	border-top: solid 1px #8833BB;
	padding : 4px;
	height: fit-content;
	margin-bottom: 0%;
}

#mainNav {
	font-family: 'Montserrat', 'Helvetica Neue', Helvetica, Arial, sans-serif;
	font-weight: 700;
	text-transform: uppercase;
	background: blue;
	border-left: solid 3px navy;
	border-top: solid 3px navy;
	border-bottom: solid 3px rgba(252,252,255,0.7);
	min-height: 90px;
	padding: 20px;
	background: -webkit-linear-gradient(to left, rgba(242, 242, 210, 0.3), white);
	background: linear-gradient(to left, rgba(242, 242, 210, 0.3), white );
}

#mainNav table .navbar-nav a.nav-text {
	background-color : rgba(242,222,255,0.6);
	border-radius: 25px;
	margin-bottom: 9px;
	margin-right: 6px;
	white-space: nowrap;
}

#mainNav table .navbar-nav li.nav-item a.nav-link {
	color: darkgreen;
	text-decoration: none;
	vertical-align: top;
	padding-right: 10px;
}

#mainNav table .navbar-nav li.nav-item a.nav-link:hover {
	color: #18BC9C;
	outline: none;
}

#contact_box {
	background: -webkit-linear-gradient(to right, rgba(252, 252, 240, 1.0), #FEFEFE);
	background: linear-gradient(to right, rgba(252, 252, 240, 1.0), #FEFEFE );
}

#squashMenuContainer {
	position:absolute;
	visibility:hidden;
	top : 0; left : 0;
	height:100%;
	width: 55%;
	z-index:100;
	border: rgba(252, 190, 190, 0.4) 2px solid;
	background-color: white;
}

#thankyou_box {
	position:absolute;
	visibility:hidden;
	top : 25%; left : 25%;
	height:50%;
	width: 50%;
	z-index:150;
	border: rgba(100, 5, 5, 0.6) 2px solid;
	background-color: lightgoldenrodyellow;
	overflow: auto;
}

.close {
	color: white;
	float: right;
	font-size: 18px;
	font-weight: bold;
}

.closer_x {
	padding:2px;
	color:purple;
	font-weight:bolder;
	font-family: sans-serif;
	border: solid 1px rgb(255, 102, 0);
	cursor:pointer;
	height: 19px;
	font-size:smaller;
}

.closer_x:hover {
	padding:2px;
	color:purple;
	font-weight:bolder;
	font-family: sans-serif;
	border: solid 1px rgb(44, 129, 44);
	cursor:pointer;
	height: 19px;
	font-size:smaller;
	background-color: rgb(248, 245, 219);
}

.items {
	display: flex;
	flex-wrap: wrap;
	margin-left: -10px;
	margin-top: -10px;
}

.items .extra-i {
	padding-left: 10%;
	padding-bottom: 4px;
	padding-right: 12px;
	font-size: 110%;
	font-family: sans-serif;
}

.items .item {
	flex: 1 0 300px;
	box-sizing: border-box;
	background: -webkit-linear-gradient(to right, rgba(242, 242, 210, 0.3), white);
	background: linear-gradient(to right, rgba(242, 242, 210, 0.3), white );
	color: #171e42;
	padding: 10px;
	margin-left: 10px;
	margin-top: 0px;
}

.PhIOtjDr_0 {
	fill:none;
	stroke:#1c1448;
	stroke-width:4.59875107;
	stroke-miterlimit:4;
	stroke-dasharray: 2948 2950;
	stroke-dashoffset: 2949;
	animation: PhIOtjDr_draw 6666ms ease-in forwards;
}

.applink {
	padding:3px;
	background-color: cornsilk;
	width:inherit;
	min-height: 100%;
	color:darkolivegreen;
	font-weight: bolder;
}

.error-message {
	visibility:hidden;
	width:75%;
	font-weight:bolder;
	color:red;
	background-color:white;
	border: solid 1px orange;
	padding:2px;
	margin:3px;
}

.extraBanner {
	text-align: 'center';
	padding-left: 10%;
	padding-right: 10%;
	font-weight:bold;
	color: #FF4400;
	padding-top:4%;
}

.fade_able {
	position:absolute;
	visibility:hidden;
	top : 10px; left : 10px;
	height:80%;
	width: 40%;
	z-index:101;
	border: rgba(252, 190, 190, 0.4) 2px solid;
	background-color: white;
	overflow:hidden;
}

.fillLower {
	border: darkred 2px solid;
	height: fit-content;
	width: 96%;
	min-height: fit-content;
	margin-left: 10px;
	padding:8px;
	background: -webkit-linear-gradient(to right, rgba(252, 252, 240, 0.4), #FEFEFE);
	background: linear-gradient(to right, rgba(252, 252, 240, 0.4), #FEFEFE );
}

.fillLowerWrap {
	width: 66%;
	margin-left:0px;
	margin-right:0px;
	padding: 8px;
	margin-top:8px;
	background: -webkit-linear-gradient(to right, white, #FAFAFF);
	background: linear-gradient(to right, white, #FAFAFF );
	margin-left: 10px;
	min-height: fit-content;
	display: table-column-group;
}

.fitMenuLower {
	width: 95%;
	height: 50%;
	margin-left:0px;
	margin-right:0px;
	padding: 8px;
	margin-top:8px;
	background: -webkit-linear-gradient(to right, white, #FAFAFF);
	background: linear-gradient(to right, white, #FAFAFF );
	margin-left: 10px;
}

.middleBanner {
	text-align: 'center';
	padding-left: 10%;
	padding-right: 10%;
	font-weight:bold;
	color: darkgreen;
	padding-top:4%;
	overflow:auto;
}

.modal {
	display: none;
	position: relative;
	z-index: 1;
	left: 0;
	top: 0;
	width: 100%;
	height: 100%;
	overflow: auto;
	background-color: rgb(0,0,0);
	background-color: rgba(0,0,0,0.4);
	-webkit-animation-name: fadeIn;
	-webkit-animation-duration: 0.4s;
	animation-name: fadeIn;
	animation-duration: 0.4s
}

.modal-content {
	position: inherit;
	top: 0;
	background-color: #fefefe;
	width: 100%;
	-webkit-animation-name: slideIn;
	-webkit-animation-duration: 0.4s;
	animation-name: slideIn;
	animation-duration: 0.4s
}

.modal-footer {
	padding: 2px 16px;
	margin-bottom: 20px;
	background-color: darkgreen;
	color: white;
}

.noselect {
	-webkit-touch-callout: none;
	-webkit-user-select: none;
	-khtml-user-select: none;
	-moz-user-select: none;
	-ms-user-select: none;
	user-select: none;
}

